def getTimeStr(frames):
    secons = int(round(frames/30.))
    if secons > 60:
        mins = secons//60
        secons = secons%60
        if mins > 60:       
            how = mins//60
            mins = mins%60
            return str(how)+'h,'+str(mins)+'m,'+str(secons)+'s'
        return str(mins)+'m,'+str(secons)+'s'
    return str(secons)+'s'

def isIn(rect, xy):
    if xy[0]<rect[0]:return False
    if xy[1]<rect[1]:return False
    if xy[0]<rect[2] and xy[1]<rect[3]:return True
    return False
    
